import { motion, useAnimate } from "motion/react";
import { forwardRef, useImperativeHandle } from "react";
export interface AnimatedIconHandle {
  startAnimation: () => void;
  stopAnimation: () => void;
}

export interface IconProps {
  size?: number;
  color?: string;
  strokeWidth?: number;
  duration?: number;
  className?: string;
}


export const Battery = forwardRef<AnimatedIconHandle, IconProps>(
  (
    {
      size = 24,
      strokeWidth = 2,
      color = "currentColor",
      className = "",
      duration = 1.2,
    },
    ref,
  ) => {
    const [scope, animate] = useAnimate();

    const start = () => {
      animate(
        ".show",

        { opacity: [0, 1, 0, 1, 0, 1, 0] },

        { duration, ease: "easeInOut" },
      );
    };
    useImperativeHandle(ref, () => ({
      startAnimation: start,
      stopAnimation: stop,
    }));
    return (
      <>
        <motion.svg
          onMouseEnter={start}
          ref={scope}
          width={size}
          height={size}
          viewBox="0 0 22 14"
          stroke={color}
          strokeWidth={strokeWidth}
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          className={`cursor-pointer ${className}`}
        >
          <path
            d="M15.4 1H3.39999C2.07451 1 1 2.07454 1 3.40002V10.6C1 11.9255 2.07451 13 3.39999 13H15.4C16.7255 13 17.8 11.9255 17.8 10.6V3.40002C17.8 2.07454 16.7255 1 15.4 1Z"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
          <path
            d="M21 8.59998V5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
          <motion.path
            initial={{ opacity: 0 }}
            className="show"
            d="M9 6V4"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
          <motion.path
            initial={{ opacity: 0 }}
            className="show"
            d="M9 9V9.03955"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </motion.svg>
      </>
    );
  },
);
